245→    private String resolveUniqueName(String spaceId, String name, Long parentId) {
246→        if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, name, parentId)) {
247→            return name;
248→        }
249→        int count = 1;
250→        while (true) {
251→            String candidate = name + "(" + count + ")";
252→            if (spaceNodeQueryManager.checkNameWithParentOnly(spaceId, candidate, parentId)) {
253→                return candidate;
254→            }
255→            count++;
