259→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
260→                                      Long parentId, Long userId, String sourceSpaceId,
261→                                      MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
262→        SpaceNodeVo spaceNodeVo = node.getData();
263→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
264→        String newNodeId = nodeIdMapping.get(oldNodeId);
265→
266→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
267→            newNodeId = "";
268→        }
269→
270→        if (newNodeId == null) {
271→            log.error("No mapping found for node: {}", oldNodeId);
272→            return;
273→        }
274→
275→        String originalName = spaceNodeVo.getName();
276→        String name = MigrationTypeEnum.CROSS_SERVER.equals(migrationType)
277→                ? resolveUniqueName(spaceId, originalName, parentId)
278→                : originalName;
279→        if (!name.equals(originalName)) {
280→            log.info("[2010-change-filename] migrate node name conflict, renamed: [{}] -> [{}], spaceId: {}, " +
281→                            "parentId: {}",
282→                    originalName,
283→                    name, spaceId, parentId);
284→        }
285→
286→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
287→                .appSpaceNodeId(newNodeId)
288→                .name(name)
289→                .type(spaceNodeVo.getType())
290→                .description(spaceNodeVo.getDescription())
291→                .spaceId(spaceId)
292→                .createdBy(userId)
293→                .updatedBy(userId)
294→                .build();
295→
296→        spaceNodeService.save(spaceNodeEntity);
297→        NodeEntity nodeEntity = treeNodeTemplate.addNode(parentId, spaceId, spaceNodeEntity.getId(), SpaceNodeEntity.class);
298→        log.info("migrate node, id: {}, appSpaceNodeId: {}, name: {}, parentId",spaceNodeEntity.getId(),spaceNodeEntity.getAppSpaceNodeId(),spaceNodeEntity.getName());
299→
300→        // 复制文件关联的版本快照
301→        versionSnapshotMigrationHelper.copyVersionSnapshots(node.getRelId(), spaceNodeEntity, spaceId, sourceSpaceId, migrationType, migrationConfig, userId);
302→
303→        if (node.getChildren() != null && !node.getChildren().isEmpty()) {
304→            for (TreeNode<SpaceNodeVo> child : node.getChildren()) {
305→                saveNodeAndChildren(child, spaceId, nodeIdMapping, nodeEntity.getId(), userId,
306→                        sourceSpaceId, migrationType, migrationConfig);
307→            }
308→        }
309→    }
