312→    private List<TreeNode<SpaceNodeVo>> deserializeTree(String json) throws IOException {
313→        ObjectMapper mapper = objectMapper.copy();
314→        mapper.addMixIn(TreeNode.class, TreeNodeMixin.class);
315→        SimpleModule module = new SimpleModule();
316→        module.addAbstractTypeMapping(RelIdProvider.class, SpaceNodeVo.class);
317→        mapper.registerModule(module);
318→        JavaType treeNodeType =
319→                mapper.getTypeFactory().constructParametricType(TreeNode.class, SpaceNodeVo.class);
320→        JavaType listType =
321→                mapper.getTypeFactory().constructCollectionType(List.class, treeNodeType);
322→        return mapper.readValue(json, listType);
323→    }
