    @Override
    public SpaceNodeMigrationTaskVo getMigrationTaskInfo(String taskId) {
        if (constProperties.isMirror()) { //mirror环境为跨服务器迁移, 从对方服务获取数据
            return collabspaceGrpcClientService.getSpaceNodeMigrationTask(taskId);
        }

        SpaceNodeMigrationTaskEntity task = spaceNodeMigrationTaskService.getByTaskId(taskId);
        ExceptionUtil.isNotNull(task, DatabaseException.QUERY_EMPTY_BY_ID);
        return new SpaceNodeMigrationTaskVo(task);
    }

    @Override
    public BatchMigrationTaskVo getBatchMigrationTaskInfo(String batchId) {
        List<SpaceNodeMigrationTaskEntity> tasks = spaceNodeMigrationTaskService.listByBatchId(batchId);
        if (tasks.isEmpty()) {
            return BatchMigrationTaskVo.builder().batchId(batchId).tasks(List.of()).build();
        }

        // 批量查询空间站名称，避免 N+1
        Set<String> spaceIds = tasks.stream().map(SpaceNodeMigrationTaskEntity::getSourceSpaceId).collect(Collectors.toSet());
        Map<String, String> spaceNameMap = new HashMap<>();
        for (String spaceId : spaceIds) {
            try {
                com.yottastudios.ns.collabspace.space.entity.SpaceEntity space = spaceService.getBySpaceId(spaceId);
                if (space != null) {
                    spaceNameMap.put(spaceId, space.getName());
                }
            } catch (Exception e) {
                log.warn("Failed to get space name for spaceId={}, error={}", spaceId, e.getMessage());
            }
        }

        List<BatchMigrationSubTaskVo> subTasks = tasks.stream().map(task -> {
            String spaceName = spaceNameMap.getOrDefault(task.getSourceSpaceId(), "");
            return new BatchMigrationSubTaskVo(task, spaceName);
        }).toList();

        return BatchMigrationTaskVo.builder().batchId(batchId).tasks(subTasks).build();
    }

    @Override
    public List<SpaceVo> listManagedSpaceForMigration(Long userId) {
        if (constProperties.isMirror()) { //mirror环境为跨服务器迁移, 从对方服务获取数据
            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
            String email = user.getEmail();
            return collabspaceGrpcClientService.listManagedSpaceForMigration(email);
        }

        List<SpaceEntity> spaceEntities = spaceQueryManager.getMemberManagedSpace(userId);
        return spaceEntities.stream()
                .map(entity -> {
                    List<SpaceAppRelEntity> spaceAppRels = spaceAppRelService.listBySpaceId(entity.getSpaceId());
                    SpaceVo vo = new SpaceVo(entity, spaceAppRels);
                    vo.setFolders(buildFolderTree(entity.getSpaceId()));
                    return vo;
                })
                .collect(Collectors.toList());
    }

    @Override
    public List<VersionSnapshotVo> listVersionSnapshot(Long spaceNodeId, Integer status) {
        List<CollabspaceVersionSnapshotEntity> list = versionSnapshotService.getByNodeId(spaceNodeId, status);
        if (list.isEmpty()){
            return new ArrayList<>();
        }
        List<Long> creatorList = new ArrayList<>(list.stream().map(CollabspaceVersionSnapshotEntity::getCreatedBy).toList());
        List<Long> operatorList = list.stream().map(CollabspaceVersionSnapshotEntity::getOperatorId).toList();
        if (!operatorList.isEmpty()){
            creatorList.addAll(operatorList);
        }
        creatorList = creatorList.stream().filter(o -> o != null && o != 0L).toList();
        List<UserSimpleInfoVo> userList = apitableGrpcClientService.getUserByIds(creatorList);
        List<VersionSnapshotVo> voList = new ArrayList<>();
        list.forEach(item -> {
            Long userId = item.getOperatorId();
            UserSimpleInfoVo operator = userList.stream().filter(o -> Objects.equals(o.getId(), userId)).findFirst().orElse(null);
            UserSimpleInfoVo creator = userList.stream().filter(o -> Objects.equals(o.getId(), item.getCreatedBy())).findFirst().orElse(null);
            String opUserName = operator == null ? "" : operator.getNickName();
            String createUserName = creator == null ? "" : creator.getNickName();
            String deleteTime = status.equals(VersionSnapshotStatusEnum.DISABLED.getValue()) ?
                    item.getUpdatedAt().toString() : "";
            voList.add(VersionSnapshotVo.builder().snapshotName(item.getSnapshotName()).id(item.getId().toString())
                    .snapshotId(item.getSnapshotId()).snapshotCreator(createUserName).
                    snapshotDeleteUser(opUserName).snapshotCreateTime(item.getCreatedAt().toString()).
                    snapshotDeleteTime(deleteTime).build());
        });
        List<VersionSnapshotVo> finalList = voList;
        finalList = finalList.stream().sorted(Comparator.comparing(VersionSnapshotVo::getSnapshotCreateTime)).toList();
        return finalList;
    }

    private List<FolderTreeNodeVo> buildFolderTree(String spaceId) {
        List<TreeNode<SpaceNodeVo>> fullTree = spaceNodeQueryManager.getSpaceNodeTreeWithoutRole(spaceId);
        return FolderTreeNodeVo.filterFromTree(fullTree);
    }
}

